    98→int
    99→getdestaddr(int fd, struct sockaddr_storage *destaddr)
   100→{
   101→    socklen_t socklen = sizeof(*destaddr);
   102→    int error         = 0;
   103→
   104→    error = getsockopt(fd, SOL_IPV6, IP6T_SO_ORIGINAL_DST, destaddr, &socklen);
   105→    if (error) { // Didn't find a proper way to detect IP version.
   106→        error = getsockopt(fd, SOL_IP, SO_ORIGINAL_DST, destaddr, &socklen);
   107→        if (error) {
   108→            return -1;
   109→        }
   110→    }
   111→    return 0;
   112→}
   113→
   114→int
   115→setnonblocking(int fd)
   116→{
   117→    int flags;
   118→    if (-1 == (flags = fcntl(fd, F_GETFL, 0))) {
   119→        flags = 0;
   120→    }
   121→    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
   122→}
   123→
   124→int
   125→create_and_bind(const char *addr, const char *port)
   126→{
   127→    struct addrinfo hints;
   128→    struct addrinfo *result, *rp;
   129→    int s, listen_sock;
   130→
   131→    memset(&hints, 0, sizeof(struct addrinfo));
   132→    hints.ai_family   = AF_UNSPEC;   /* Return IPv4 and IPv6 choices */
   133→    hints.ai_socktype = SOCK_STREAM; /* We want a TCP socket */
   134→
   135→    s = getaddrinfo(addr, port, &hints, &result);
   136→    if (s != 0) {
   137→        LOGI("getaddrinfo: %s", gai_strerror(s));
   138→        return -1;
   139→    }
   140→
   141→    for (rp = result; rp != NULL; rp = rp->ai_next) {
   142→        listen_sock = socket(rp->ai_family, rp->ai_socktype, rp->ai_protocol);
   143→        if (listen_sock == -1) {
   144→            continue;
   145→        }
   146→
   147→        int opt = 1;
   148→        setsockopt(listen_sock, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));
   149→#ifdef SO_NOSIGPIPE
   150→        setsockopt(listen_sock, SOL_SOCKET, SO_NOSIGPIPE, &opt, sizeof(opt));
   151→#endif
   152→        int err = set_reuseport(listen_sock);
   153→        if (err == 0) {
   154→            LOGI("tcp port reuse enabled");
   155→        }
   156→
   157→        s = bind(listen_sock, rp->ai_addr, rp->ai_addrlen);
   158→        if (s == 0) {
   159→            /* We managed to bind successfully! */
   160→            break;
   161→        } else {
   162→            ERROR("bind");
   163→        }
   164→
   165→        close(listen_sock);
   166→    }
   167→
   168→    if (rp == NULL) {
   169→        LOGE("Could not bind");
   170→        return -1;
   171→    }
   172→
   173→    freeaddrinfo(result);
   174→
   175→    return listen_sock;
   176→}
   177→
   178→static void
   179→server_recv_cb(EV_P_ ev_io *w, int revents)
   180→{
   181→    server_ctx_t *server_recv_ctx = (server_ctx_t *)w;
   182→    server_t *server              = server_recv_ctx->server;
   183→    remote_t *remote              = server->remote;
   184→
   185→    ssize_t r = recv(server->fd, remote->buf->array + remote->buf->len,
   186→                     BUF_SIZE - remote->buf->len, 0);
   187→
   188→    if (r == 0) {
   189→        // connection closed
   190→        close_and_free_remote(EV_A_ remote);
   191→        close_and_free_server(EV_A_ server);
   192→        return;
   193→    } else if (r == -1) {
   194→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   195→            // no data
   196→            // continue to wait for recv
   197→            return;
   198→        } else {
   199→            ERROR("server recv");
   200→            close_and_free_remote(EV_A_ remote);
   201→            close_and_free_server(EV_A_ server);
   202→            return;
   203→        }
   204→    }
   205→
   206→    remote->buf->len += r;
   207→
   208→    if (verbose) {
   209→        uint16_t port = 0;
   210→        char ipstr[INET6_ADDRSTRLEN];
   211→        memset(&ipstr, 0, INET6_ADDRSTRLEN);
   212→
   213→        if (AF_INET == server->destaddr.ss_family) {
   214→            struct sockaddr_in *sa = (struct sockaddr_in *)&(server->destaddr);
   215→            dns_ntop(AF_INET, &(sa->sin_addr), ipstr, INET_ADDRSTRLEN);
   216→            port = ntohs(sa->sin_port);
   217→        } else {
   218→            // TODO: The code below need to be test in IPv6 envirment, which I
   219→            //       don't have.
   220→            struct sockaddr_in6 *sa = (struct sockaddr_in6 *)&(server->destaddr);
   221→            dns_ntop(AF_INET6, &(sa->sin6_addr), ipstr, INET6_ADDRSTRLEN);
   222→            port = ntohs(sa->sin6_port);
   223→        }
   224→
   225→        LOGI("redir to %s:%d, len=%zu, recv=%zd", ipstr, port, remote->buf->len, r);
   226→    }
   227→
   228→    if (auth) {
   229→        ss_gen_hash(remote->buf, &remote->counter, server->e_ctx, BUF_SIZE);
   230→    }
   231→
   232→    if (!remote->send_ctx->connected) {
   233→        // SNI
   234→        int ret       = 0;
   235→        uint16_t port = 0;
   236→
   237→        if (AF_INET6 == server->destaddr.ss_family) { // IPv6
   238→            port = ntohs(((struct sockaddr_in6 *)&(server->destaddr))->sin6_port);
   239→        } else {                             // IPv4
   240→            port = ntohs(((struct sockaddr_in *)&(server->destaddr))->sin_port);
   241→        }
   242→        if (port == http_protocol->default_port)
   243→            ret = http_protocol->parse_packet(remote->buf->array,
   244→                                              remote->buf->len, &server->hostname);
   245→        else if (port == tls_protocol->default_port)
   246→            ret = tls_protocol->parse_packet(remote->buf->array,
   247→                                             remote->buf->len, &server->hostname);
   248→        if (ret > 0) {
   249→            server->hostname_len = ret;
   250→        }
   251→
   252→        ev_io_stop(EV_A_ & server_recv_ctx->io);
   253→        ev_io_start(EV_A_ & remote->send_ctx->io);
   254→        return;
   255→    }
   256→
   257→    int err = ss_encrypt(remote->buf, server->e_ctx, BUF_SIZE);
   258→
   259→    if (err) {
   260→        LOGE("invalid password or cipher");
   261→        close_and_free_remote(EV_A_ remote);
   262→        close_and_free_server(EV_A_ server);
   263→        return;
   264→    }
   265→
   266→    int s = send(remote->fd, remote->buf->array, remote->buf->len, 0);
   267→
   268→    if (s == -1) {
   269→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   270→            // no data, wait for send
   271→            remote->buf->idx = 0;
   272→            ev_io_stop(EV_A_ & server_recv_ctx->io);
   273→            ev_io_start(EV_A_ & remote->send_ctx->io);
   274→            return;
   275→        } else {
   276→            ERROR("send");
   277→            close_and_free_remote(EV_A_ remote);
   278→            close_and_free_server(EV_A_ server);
   279→            return;
   280→        }
   281→    } else if (s < remote->buf->len) {
   282→        remote->buf->len -= s;
   283→        remote->buf->idx  = s;
   284→        ev_io_stop(EV_A_ & server_recv_ctx->io);
   285→        ev_io_start(EV_A_ & remote->send_ctx->io);
   286→        return;
   287→    } else {
   288→        remote->buf->idx = 0;
   289→        remote->buf->len = 0;
   290→    }
   291→}
   292→
   293→static void
   294→server_send_cb(EV_P_ ev_io *w, int revents)
   295→{
   296→    server_ctx_t *server_send_ctx = (server_ctx_t *)w;
   297→    server_t *server              = server_send_ctx->server;
   298→    remote_t *remote              = server->remote;
   299→    if (server->buf->len == 0) {
   300→        // close and free
   301→        close_and_free_remote(EV_A_ remote);
   302→        close_and_free_server(EV_A_ server);
   303→        return;
   304→    } else {
   305→        // has data to send
   306→        ssize_t s = send(server->fd, server->buf->array + server->buf->idx,
   307→                         server->buf->len, 0);
   308→        if (s == -1) {
   309→            if (errno != EAGAIN && errno != EWOULDBLOCK) {
   310→                ERROR("send");
   311→                close_and_free_remote(EV_A_ remote);
   312→                close_and_free_server(EV_A_ server);
   313→            }
   314→            return;
   315→        } else if (s < server->buf->len) {
   316→            // partly sent, move memory, wait for the next time to send
   317→            server->buf->len -= s;
   318→            server->buf->idx += s;
   319→            return;
   320→        } else {
   321→            // all sent out, wait for reading
   322→            server->buf->len = 0;
   323→            server->buf->idx = 0;
   324→            ev_io_stop(EV_A_ & server_send_ctx->io);
   325→            ev_io_start(EV_A_ & remote->recv_ctx->io);
   326→        }
   327→    }
   328→}
   329→
   330→static void
   331→remote_timeout_cb(EV_P_ ev_timer *watcher, int revents)
   332→{
   333→    remote_ctx_t *remote_ctx
   334→        = cork_container_of(watcher, remote_ctx_t, watcher);
   335→
   336→    remote_t *remote = remote_ctx->remote;
   337→    server_t *server = remote->server;
   338→
   339→    ev_timer_stop(EV_A_ watcher);
   340→
   341→    close_and_free_remote(EV_A_ remote);
   342→    close_and_free_server(EV_A_ server);
   343→}
   344→
   345→static void
   346→remote_recv_cb(EV_P_ ev_io *w, int revents)
   347→{
   348→    remote_ctx_t *remote_recv_ctx = (remote_ctx_t *)w;
   349→    remote_t *remote              = remote_recv_ctx->remote;
   350→    server_t *server              = remote->server;
   351→
   352→    ev_timer_again(EV_A_ & remote->recv_ctx->watcher);
   353→
   354→    ssize_t r = recv(remote->fd, server->buf->array, BUF_SIZE, 0);
   355→
   356→    if (r == 0) {
   357→        // connection closed
   358→        close_and_free_remote(EV_A_ remote);
   359→        close_and_free_server(EV_A_ server);
   360→        return;
   361→    } else if (r == -1) {
   362→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   363→            // no data
   364→            // continue to wait for recv
   365→            return;
   366→        } else {
   367→            ERROR("remote recv");
   368→            close_and_free_remote(EV_A_ remote);
   369→            close_and_free_server(EV_A_ server);
   370→            return;
   371→        }
   372→    }
   373→
   374→    server->buf->len = r;
   375→
   376→    int err = ss_decrypt(server->buf, server->d_ctx, BUF_SIZE);
   377→    if (err) {
   378→        LOGE("invalid password or cipher");
   379→        close_and_free_remote(EV_A_ remote);
   380→        close_and_free_server(EV_A_ server);
   381→        return;
   382→    }
   383→    int s = send(server->fd, server->buf->array, server->buf->len, 0);
   384→
   385→    if (s == -1) {
   386→        if (errno == EAGAIN || errno == EWOULDBLOCK) {
   387→            // no data, wait for send
   388→            server->buf->idx = 0;
   389→            ev_io_stop(EV_A_ & remote_recv_ctx->io);
   390→            ev_io_start(EV_A_ & server->send_ctx->io);
   391→        } else {
   392→            ERROR("send");
   393→            close_and_free_remote(EV_A_ remote);
   394→            close_and_free_server(EV_A_ server);
   395→        }
   396→    } else if (s < server->buf->len) {
   397→        server->buf->len -= s;
   398→        server->buf->idx  = s;
   399→        ev_io_stop(EV_A_ & remote_recv_ctx->io);
   400→        ev_io_start(EV_A_ & server->send_ctx->io);
   401→    }
   402→
   403→    // Disable TCP_NODELAY after the first response are sent
   404→    int opt = 0;
   405→    setsockopt(server->fd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   406→    setsockopt(remote->fd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   407→}
   408→
   409→static void
   410→remote_send_cb(EV_P_ ev_io *w, int revents)
   411→{
   412→    remote_ctx_t *remote_send_ctx = (remote_ctx_t *)w;
   413→    remote_t *remote              = remote_send_ctx->remote;
   414→    server_t *server              = remote->server;
   415→
   416→    if (!remote_send_ctx->connected) {
   417→        struct sockaddr_storage addr;
   418→        memset(&addr, 0, sizeof(struct sockaddr_storage));
   419→        socklen_t len = sizeof addr;
   420→        int r         = getpeername(remote->fd, (struct sockaddr *)&addr, &len);
   421→        if (r == 0) {
   422→            remote_send_ctx->connected = 1;
   423→            ev_io_stop(EV_A_ & remote_send_ctx->io);
   424→            ev_io_stop(EV_A_ & server->recv_ctx->io);
   425→            ev_timer_stop(EV_A_ & remote_send_ctx->watcher);
   426→            ev_timer_start(EV_A_ & remote->recv_ctx->watcher);
   427→
   428→            // send destaddr
   429→            buffer_t ss_addr_to_send;
   430→            buffer_t *abuf = &ss_addr_to_send;
   431→            balloc(abuf, BUF_SIZE);
   432→
   433→            if (server->hostname_len > 0) { // HTTP/SNI
   434→                uint16_t port;
   435→                if (AF_INET6 == server->destaddr.ss_family) { // IPv6
   436→                    port = (((struct sockaddr_in6 *)&(server->destaddr))->sin6_port);
   437→                } else {                             // IPv4
   438→                    port = (((struct sockaddr_in *)&(server->destaddr))->sin_port);
   439→                }
   440→
   441→                abuf->array[abuf->len++] = 3;          // Type 3 is hostname
   442→                abuf->array[abuf->len++] = server->hostname_len;
   443→                memcpy(abuf->array + abuf->len, server->hostname, server->hostname_len);
   444→                abuf->len += server->hostname_len;
   445→                memcpy(abuf->array + abuf->len, &port, 2);
   446→            } else if (AF_INET6 == server->destaddr.ss_family) { // IPv6
   447→                abuf->array[abuf->len++] = 4;          // Type 4 is IPv6 address
   448→
   449→                size_t in6_addr_len = sizeof(struct in6_addr);
   450→                memcpy(abuf->array + abuf->len,
   451→                       &(((struct sockaddr_in6 *)&(server->destaddr))->sin6_addr),
   452→                       in6_addr_len);
   453→                abuf->len += in6_addr_len;
   454→                memcpy(abuf->array + abuf->len,
   455→                       &(((struct sockaddr_in6 *)&(server->destaddr))->sin6_port),
   456→                       2);
   457→            } else {                             // IPv4
   458→                abuf->array[abuf->len++] = 1; // Type 1 is IPv4 address
   459→
   460→                size_t in_addr_len = sizeof(struct in_addr);
   461→                memcpy(abuf->array + abuf->len,
   462→                       &((struct sockaddr_in *)&(server->destaddr))->sin_addr, in_addr_len);
   463→                abuf->len += in_addr_len;
   464→                memcpy(abuf->array + abuf->len,
   465→                       &((struct sockaddr_in *)&(server->destaddr))->sin_port, 2);
   466→            }
   467→
   468→            abuf->len += 2;
   469→
   470→            if (auth) {
   471→                abuf->array[0] |= ONETIMEAUTH_FLAG;
   472→                ss_onetimeauth(abuf, server->e_ctx->evp.iv, BUF_SIZE);
   473→            }
   474→
   475→            brealloc(remote->buf, remote->buf->len + abuf->len, BUF_SIZE);
   476→            memmove(remote->buf->array + abuf->len, remote->buf->array, remote->buf->len);
   477→            memcpy(remote->buf->array, abuf->array, abuf->len);
   478→            remote->buf->len += abuf->len;
   479→            bfree(abuf);
   480→
   481→            int err = ss_encrypt(remote->buf, server->e_ctx, BUF_SIZE);
   482→            if (err) {
   483→                LOGE("invalid password or cipher");
   484→                close_and_free_remote(EV_A_ remote);
   485→                close_and_free_server(EV_A_ server);
   486→                return;
   487→            }
   488→
   489→            ev_io_start(EV_A_ & remote->recv_ctx->io);
   490→        } else {
   491→            ERROR("getpeername");
   492→            // not connected
   493→            close_and_free_remote(EV_A_ remote);
   494→            close_and_free_server(EV_A_ server);
   495→            return;
   496→        }
   497→    }
   498→
   499→    if (remote->buf->len == 0) {
   500→        // close and free
   501→        close_and_free_remote(EV_A_ remote);
   502→        close_and_free_server(EV_A_ server);
   503→        return;
   504→    } else {
   505→        // has data to send
   506→        ssize_t s = send(remote->fd, remote->buf->array + remote->buf->idx,
   507→                         remote->buf->len, 0);
   508→        if (s == -1) {
   509→            if (errno != EAGAIN && errno != EWOULDBLOCK) {
   510→                ERROR("send");
   511→                // close and free
   512→                close_and_free_remote(EV_A_ remote);
   513→                close_and_free_server(EV_A_ server);
   514→            }
   515→            return;
   516→        } else if (s < remote->buf->len) {
   517→            // partly sent, move memory, wait for the next time to send
   518→            remote->buf->len -= s;
   519→            remote->buf->idx += s;
   520→            return;
   521→        } else {
   522→            // all sent out, wait for reading
   523→            remote->buf->len = 0;
   524→            remote->buf->idx = 0;
   525→            ev_io_stop(EV_A_ & remote_send_ctx->io);
   526→            ev_io_start(EV_A_ & server->recv_ctx->io);
   527→        }
   528→    }
   529→}
