   531→static remote_t *
   532→new_remote(int fd, int timeout)
   533→{
   534→    remote_t *remote = ss_malloc(sizeof(remote_t));
   535→    memset(remote, 0, sizeof(remote_t));
   536→
   537→    remote->recv_ctx            = ss_malloc(sizeof(remote_ctx_t));
   538→    remote->send_ctx            = ss_malloc(sizeof(remote_ctx_t));
   539→    remote->buf                 = ss_malloc(sizeof(buffer_t));
   540→    balloc(remote->buf, BUF_SIZE);
   541→    memset(remote->recv_ctx, 0, sizeof(remote_ctx_t));
   542→    memset(remote->send_ctx, 0, sizeof(remote_ctx_t));
   543→    remote->fd                  = fd;
   544→    remote->recv_ctx->remote    = remote;
   545→    remote->recv_ctx->connected = 0;
   546→    remote->send_ctx->remote    = remote;
   547→    remote->send_ctx->connected = 0;
   548→
   549→    ev_io_init(&remote->recv_ctx->io, remote_recv_cb, fd, EV_READ);
   550→    ev_io_init(&remote->send_ctx->io, remote_send_cb, fd, EV_WRITE);
   551→    ev_timer_init(&remote->send_ctx->watcher, remote_timeout_cb,
   552→                  min(MAX_CONNECT_TIMEOUT, timeout), 0);
   553→    ev_timer_init(&remote->recv_ctx->watcher, remote_timeout_cb,
   554→                  timeout, 0);
   555→
   556→    return remote;
   557→}
   558→
   559→static void
   560→free_remote(remote_t *remote)
   561→{
   562→    if (remote != NULL) {
   563→        if (remote->server != NULL) {
   564→            remote->server->remote = NULL;
   565→        }
   566→        if (remote->buf != NULL) {
   567→            bfree(remote->buf);
   568→            ss_free(remote->buf);
   569→        }
   570→        ss_free(remote->recv_ctx);
   571→        ss_free(remote->send_ctx);
   572→        ss_free(remote);
   573→    }
   574→}
   575→
   576→static void
   577→close_and_free_remote(EV_P_ remote_t *remote)
   578→{
   579→    if (remote != NULL) {
   580→        ev_timer_stop(EV_A_ & remote->send_ctx->watcher);
   581→        ev_timer_stop(EV_A_ & remote->recv_ctx->watcher);
   582→        ev_io_stop(EV_A_ & remote->send_ctx->io);
   583→        ev_io_stop(EV_A_ & remote->recv_ctx->io);
   584→        close(remote->fd);
   585→        free_remote(remote);
   586→    }
   587→}
