   625→
   626→static void
   627→free_server(server_t *server)
   628→{
   629→    if (server != NULL) {
   630→        if (server->hostname != NULL) {
   631→            ss_free(server->hostname);
   632→        }
   633→        if (server->remote != NULL) {
   634→            server->remote->server = NULL;
   635→        }
   636→        if (server->e_ctx != NULL) {
   637→            cipher_context_release(&server->e_ctx->evp);
   638→            ss_free(server->e_ctx);
   639→        }
   640→        if (server->d_ctx != NULL) {
   641→            cipher_context_release(&server->d_ctx->evp);
   642→            ss_free(server->d_ctx);
   643→        }
   644→        if (server->buf != NULL) {
   645→            bfree(server->buf);
   646→            ss_free(server->buf);
   647→        }
   648→        ss_free(server->recv_ctx);
   649→        ss_free(server->send_ctx);
   650→        ss_free(server);
   651→    }
   652→}
   653→
   654→static void
   655→close_and_free_server(EV_P_ server_t *server)
   656→{
   657→    if (server != NULL) {
   658→        ev_io_stop(EV_A_ & server->send_ctx->io);
   659→        ev_io_stop(EV_A_ & server->recv_ctx->io);
   660→        close(server->fd);
   661→        free_server(server);
   662→    }
   663→}
