   665→static void
   666→accept_cb(EV_P_ ev_io *w, int revents)
   667→{
   668→    listen_ctx_t *listener = (listen_ctx_t *)w;
   669→    struct sockaddr_storage destaddr;
   670→    memset(&destaddr, 0, sizeof(struct sockaddr_storage));
   671→
   672→    int err;
   673→
   674→    int serverfd = accept(listener->fd, NULL, NULL);
   675→    if (serverfd == -1) {
   676→        ERROR("accept");
   677→        return;
   678→    }
   679→
   680→    err = getdestaddr(serverfd, &destaddr);
   681→    if (err) {
   682→        ERROR("getdestaddr");
   683→        return;
   684→    }
   685→
   686→    setnonblocking(serverfd);
   687→    int opt = 1;
   688→    setsockopt(serverfd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   689→#ifdef SO_NOSIGPIPE
   690→    setsockopt(serverfd, SOL_SOCKET, SO_NOSIGPIPE, &opt, sizeof(opt));
   691→#endif
   692→
   693→    int index                    = rand() % listener->remote_num;
   694→    struct sockaddr *remote_addr = listener->remote_addr[index];
   695→
   696→    int remotefd = socket(remote_addr->sa_family, SOCK_STREAM, IPPROTO_TCP);
   697→    if (remotefd == -1) {
   698→        ERROR("socket");
   699→        return;
   700→    }
   701→
   702→    // Set flags
   703→    setsockopt(remotefd, SOL_TCP, TCP_NODELAY, &opt, sizeof(opt));
   704→#ifdef SO_NOSIGPIPE
   705→    setsockopt(remotefd, SOL_SOCKET, SO_NOSIGPIPE, &opt, sizeof(opt));
   706→#endif
   707→
   708→    // Enable TCP keepalive feature
   709→    int keepAlive    = 1;
   710→    int keepIdle     = 40;
   711→    int keepInterval = 20;
   712→    int keepCount    = 5;
   713→    setsockopt(remotefd, SOL_SOCKET, SO_KEEPALIVE, (void *)&keepAlive, sizeof(keepAlive));
   714→    setsockopt(remotefd, SOL_TCP, TCP_KEEPIDLE, (void *)&keepIdle, sizeof(keepIdle));
   715→    setsockopt(remotefd, SOL_TCP, TCP_KEEPINTVL, (void *)&keepInterval, sizeof(keepInterval));
   716→    setsockopt(remotefd, SOL_TCP, TCP_KEEPCNT, (void *)&keepCount, sizeof(keepCount));
   717→
   718→    // Set non blocking
   719→    setnonblocking(remotefd);
   720→
   721→    // Enable MPTCP
   722→    if (listener->mptcp == 1) {
   723→        int err = setsockopt(remotefd, SOL_TCP, MPTCP_ENABLED, &opt, sizeof(opt));
   724→        if (err == -1) {
   725→            ERROR("failed to enable multipath TCP");
   726→        }
   727→    }
   728→
   729→    server_t *server = new_server(serverfd, listener->method);
   730→    remote_t *remote = new_remote(remotefd, listener->timeout);
   731→    server->remote   = remote;
   732→    remote->server   = server;
   733→    server->destaddr = destaddr;
   734→
   735→    int r = connect(remotefd, remote_addr, get_sockaddr_len(remote_addr));
   736→
   737→    if (r == -1 && errno != CONNECT_IN_PROGRESS) {
   738→        ERROR("connect");
   739→        close_and_free_remote(EV_A_ remote);
   740→        close_and_free_server(EV_A_ server);
   741→        return;
   742→    }
   743→
   744→    // listen to remote connected event
   745→    ev_io_start(EV_A_ & remote->send_ctx->io);
   746→    ev_timer_start(EV_A_ & remote->send_ctx->watcher);
   747→    ev_io_start(EV_A_ & server->recv_ctx->io);
   748→}
