   757→int
   758→main(int argc, char **argv)
   759→{
   760→    srand(time(NULL));
   761→
   762→    int i, c;
   763→    int pid_flags    = 0;
   764→    int mptcp        = 0;
   765→    int mtu          = 0;
   766→    char *user       = NULL;
   767→    char *local_port = NULL;
   768→    char *local_addr = NULL;
   769→    char *password   = NULL;
   770→    char *timeout    = NULL;
   771→    char *method     = NULL;
   772→    char *pid_path   = NULL;
   773→    char *conf_path  = NULL;
   774→
   775→    int remote_num = 0;
   776→    ss_addr_t remote_addr[MAX_REMOTE_NUM];
   777→    char *remote_port = NULL;
   778→
   779→    int option_index                    = 0;
   780→    static struct option long_options[] = {
   781→        { "mtu",   required_argument, 0, 0 },
   782→        { "mptcp", no_argument,       0, 0 },
   783→        { "help",  no_argument,       0, 0 },
   784→        {       0,                 0, 0, 0 }
   785→    };
   786→
   787→    opterr = 0;
   788→
   789→    USE_TTY();
   790→
   791→    while ((c = getopt_long(argc, argv, "f:s:p:l:k:t:m:c:b:a:n:huUvA6",
   792→                            long_options, &option_index)) != -1) {
   793→        switch (c) {
   794→        case 0:
   795→            if (option_index == 0) {
   796→                mtu = atoi(optarg);
   797→                LOGI("set MTU to %d", mtu);
   798→            } else if (option_index == 1) {
   799→                mptcp = 1;
   800→                LOGI("enable multipath TCP");
   801→            } else if (option_index == 2) {
   802→                usage();
   803→                exit(EXIT_SUCCESS);
   804→            }
   805→            break;
   806→        case 's':
   807→            if (remote_num < MAX_REMOTE_NUM) {
   808→                remote_addr[remote_num].host   = optarg;
   809→                remote_addr[remote_num++].port = NULL;
   810→            }
   811→            break;
   812→        case 'p':
   813→            remote_port = optarg;
   814→            break;
   815→        case 'l':
   816→            local_port = optarg;
   817→            break;
   818→        case 'k':
   819→            password = optarg;
   820→            break;
   821→        case 'f':
   822→            pid_flags = 1;
   823→            pid_path  = optarg;
   824→            break;
   825→        case 't':
   826→            timeout = optarg;
   827→            break;
   828→        case 'm':
   829→            method = optarg;
   830→            break;
   831→        case 'c':
   832→            conf_path = optarg;
   833→            break;
   834→        case 'b':
   835→            local_addr = optarg;
   836→            break;
   837→        case 'a':
   838→            user = optarg;
   839→            break;
   840→#ifdef HAVE_SETRLIMIT
   841→        case 'n':
   842→            nofile = atoi(optarg);
   843→            break;
   844→#endif
   845→        case 'u':
   846→            mode = TCP_AND_UDP;
   847→            break;
   848→        case 'U':
   849→            mode = UDP_ONLY;
   850→            break;
   851→        case 'v':
   852→            verbose = 1;
   853→            break;
   854→        case 'h':
   855→            usage();
   856→            exit(EXIT_SUCCESS);
   857→        case 'A':
   858→            auth = 1;
   859→            break;
   860→        case '6':
   861→            ipv6first = 1;
   862→            break;
   863→        case '?':
   864→            // The option character is not recognized.
   865→            LOGE("Unrecognized option: %s", optarg);
   866→            opterr = 1;
   867→            break;
   868→        }
   869→    }
   870→
   871→    if (opterr) {
   872→        usage();
   873→        exit(EXIT_FAILURE);
   874→    }
   875→
   876→    if (argc == 1) {
   877→        if (conf_path == NULL) {
   878→            conf_path = DEFAULT_CONF_PATH;
   879→        }
   880→    }
   881→
   882→    if (conf_path != NULL) {
   883→        jconf_t *conf = read_jconf(conf_path);
   884→        if (remote_num == 0) {
   885→            remote_num = conf->remote_num;
   886→            for (i = 0; i < remote_num; i++)
   887→                remote_addr[i] = conf->remote_addr[i];
   888→        }
   889→        if (remote_port == NULL) {
   890→            remote_port = conf->remote_port;
   891→        }
   892→        if (local_addr == NULL) {
   893→            local_addr = conf->local_addr;
   894→        }
   895→        if (local_port == NULL) {
   896→            local_port = conf->local_port;
   897→        }
   898→        if (password == NULL) {
   899→            password = conf->password;
   900→        }
   901→        if (method == NULL) {
   902→            method = conf->method;
   903→        }
   904→        if (timeout == NULL) {
   905→            timeout = conf->timeout;
   906→        }
   907→        if (user == NULL) {
   908→            user = conf->user;
   909→        }
   910→        if (auth == 0) {
   911→            auth = conf->auth;
   912→        }
   913→        if (mtu == 0) {
   914→            mtu = conf->mtu;
   915→        }
   916→        if (mptcp == 0) {
   917→            mptcp = conf->mptcp;
   918→        }
   919→#ifdef HAVE_SETRLIMIT
   920→        if (nofile == 0) {
   921→            nofile = conf->nofile;
   922→        }
   923→#endif
   924→    }
   925→
   926→    if (remote_num == 0 || remote_port == NULL ||
   927→        local_port == NULL || password == NULL) {
   928→        usage();
   929→        exit(EXIT_FAILURE);
   930→    }
   931→
   932→    if (method == NULL) {
   933→        method = "rc4-md5";
   934→    }
   935→
   936→    if (timeout == NULL) {
   937→        timeout = "600";
   938→    }
   939→
   940→#ifdef HAVE_SETRLIMIT
   941→    /*
   942→     * no need to check the return value here since we will show
   943→     * the user an error message if setrlimit(2) fails
   944→     */
   945→    if (nofile > 1024) {
   946→        if (verbose) {
   947→            LOGI("setting NOFILE to %d", nofile);
   948→        }
   949→        set_nofile(nofile);
   950→    }
   951→#endif
   952→
   953→    if (local_addr == NULL) {
   954→        local_addr = "127.0.0.1";
   955→    }
   956→
   957→    if (pid_flags) {
   958→        USE_SYSLOG(argv[0]);
   959→        daemonize(pid_path);
   960→    }
   961→
   962→    if (ipv6first) {
   963→        LOGI("resolving hostname to IPv6 address first");
   964→    }
   965→
   966→    if (auth) {
   967→        LOGI("onetime authentication enabled");
   968→    }
   969→
   970→    // ignore SIGPIPE
   971→    signal(SIGPIPE, SIG_IGN);
   972→    signal(SIGABRT, SIG_IGN);
   973→    signal(SIGINT, signal_cb);
   974→    signal(SIGTERM, signal_cb);
   975→
   976→    // Setup keys
   977→    LOGI("initializing ciphers... %s", method);
   978→    int m = enc_init(password, method);
   979→
   980→    // Setup proxy context
   981→    listen_ctx_t listen_ctx;
   982→    listen_ctx.remote_num  = remote_num;
   983→    listen_ctx.remote_addr = ss_malloc(sizeof(struct sockaddr *) * remote_num);
   984→    memset(listen_ctx.remote_addr, 0, sizeof(struct sockaddr *) * remote_num);
   985→    for (int i = 0; i < remote_num; i++) {
   986→        char *host = remote_addr[i].host;
   987→        char *port = remote_addr[i].port == NULL ? remote_port :
   988→                     remote_addr[i].port;
   989→        struct sockaddr_storage *storage = ss_malloc(sizeof(struct sockaddr_storage));
   990→        memset(storage, 0, sizeof(struct sockaddr_storage));
   991→        if (get_sockaddr(host, port, storage, 1, ipv6first) == -1) {
   992→            FATAL("failed to resolve the provided hostname");
   993→        }
   994→        listen_ctx.remote_addr[i] = (struct sockaddr *)storage;
   995→    }
   996→    listen_ctx.timeout = atoi(timeout);
   997→    listen_ctx.method  = m;
   998→    listen_ctx.mptcp   = mptcp;
   999→
  1000→    struct ev_loop *loop = EV_DEFAULT;
  1001→
  1002→    if (mode != UDP_ONLY) {
  1003→        // Setup socket
  1004→        int listenfd;
  1005→        listenfd = create_and_bind(local_addr, local_port);
  1006→        if (listenfd == -1) {
  1007→            FATAL("bind() error");
  1008→        }
  1009→        if (listen(listenfd, SOMAXCONN) == -1) {
  1010→            FATAL("listen() error");
  1011→        }
  1012→        setnonblocking(listenfd);
  1013→
  1014→        listen_ctx.fd = listenfd;
  1015→
  1016→        ev_io_init(&listen_ctx.io, accept_cb, listenfd, EV_READ);
  1017→        ev_io_start(loop, &listen_ctx.io);
  1018→    }
  1019→
  1020→    // Setup UDP
  1021→    if (mode != TCP_ONLY) {
  1022→        LOGI("UDP relay enabled");
  1023→        init_udprelay(local_addr, local_port, listen_ctx.remote_addr[0],
  1024→                      get_sockaddr_len(listen_ctx.remote_addr[0]), mtu, m, auth, listen_ctx.timeout, NULL);
  1025→    }
  1026→
  1027→    if (mode == UDP_ONLY) {
